import React, { useRef, useMemo } from 'react';
import { MediaPlayer, MediaProvider, Poster } from '@vidstack/react';
import { defaultLayoutIcons, DefaultVideoLayout } from '@vidstack/react/player/layouts/default';
import Hls from 'hls.js';
import { SourceResult, SourceType } from '../types';

interface PlayerProps {
  source: SourceResult;
  title: string;
  poster?: string;
  onProgress?: (percent: number) => void;
  onComplete?: () => void;
}

const Player: React.FC<PlayerProps> = ({ source, title, poster, onProgress, onComplete }) => {
  const playerRef = useRef<any>(null);

  const hlsConfig = useMemo(() => {
    if (!Hls.isSupported()) return {};

    return {
      fetchSetup: (url: string, init: RequestInit) => {
        const isKey = url.includes('.key') || url.includes('/keys/') || url === source.keyUrl;

        if (isKey || (source.keyUrl && url.includes(source.keyUrl))) {
          const targetUrl = source.keyUrl || url;
          const proxyBase = 'https://test.cors.workers.dev/?';
          return new Request(proxyBase + encodeURIComponent(targetUrl), init);
        }

        return new Request(url, init);
      },
      xhrSetup: (xhr: XMLHttpRequest, url: string) => {
        if (url.includes('.key')) xhr.withCredentials = false;
      },
      enableWorker: true,
      lowLatencyMode: true,
      backBufferLength: 90,
      maxBufferLength: 60,
    };
  }, [source.url, source.keyUrl]);

  const handleTimeUpdate = (event: any) => {
    if (!event?.detail) return;
    const { currentTime, duration } = event.detail;
    if (duration > 0) {
      const percent = (currentTime / duration) * 100;
      onProgress?.(percent);
      if (percent >= 98) onComplete?.();
    }
  };

  if (source.type === SourceType.EMBED) {
    return (
      <div className="relative aspect-video w-full bg-black rounded-2xl overflow-hidden shadow-2xl border border-white/5">
        <iframe 
          src={source.url} 
          className="w-full h-full border-0" 
          allowFullScreen 
          referrerPolicy="no-referrer" 
        />
      </div>
    );
  }

  return (
    <div className="relative aspect-video w-full bg-slate-950 rounded-2xl overflow-hidden shadow-2xl group border border-white/5 transition-all">
      <div className="absolute top-5 right-5 z-40 bg-black/60 backdrop-blur-md px-3 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest text-white/80 border border-white/10 opacity-0 group-hover:opacity-100 transition-opacity flex items-center gap-2 pointer-events-none">
        <div className={`w-1.5 h-1.5 rounded-full ${source.keyUrl ? 'bg-purple-500' : 'bg-blue-500'}`}></div>
        {source.provider} • {source.category}
      </div>

      <MediaPlayer
        ref={playerRef}
        title={title}
        src={source.url}
        onTimeUpdate={handleTimeUpdate}
        crossOrigin
        playsInline
        className="w-full h-full"
      >
        <MediaProvider {...({ hlsConfig } as any)}>
          {poster && <Poster src={poster} alt={title} className="vds-poster" />}
        </MediaProvider>
        <DefaultVideoLayout icons={defaultLayoutIcons} />
      </MediaPlayer>

      <style>{`
        .vds-poster {
          position: absolute;
          inset: 0;
          width: 100%;
          height: 100%;
          object-fit: cover;
          opacity: 0.15;
          filter: blur(50px);
          transition: opacity 0.5s ease;
        }
        .vds-media-player[data-can-play] .vds-poster {
          opacity: 0;
          pointer-events: none;
        }
      `}</style>
    </div>
  );
};

export default Player;

import React, { useState, useMemo } from 'react';
import { MediaPlayer, MediaProvider, Poster } from '@vidstack/react';
import { defaultLayoutIcons, DefaultVideoLayout } from '@vidstack/react/player/layouts/default';
import Hls from 'hls.js';
import { SourceResult, SourceType } from '../types';

interface AnimePlayerProps {
  sources: SourceResult[];
  title: string;
  poster?: string;
  onProgress?: (percent: number) => void;
  onComplete?: () => void;
}

function resolveSourceUrl(url: string): string {
  if (!url) return '';
  if (url.startsWith('/apivtwo/')) {
    return `https://allanime.day${url}`;
  }
  return url;
}

const AnimePlayer: React.FC<AnimePlayerProps> = ({ sources, title, poster, onProgress, onComplete }) => {
  const [activeSourceIndex, setActiveSourceIndex] = useState(0);
  const activeSource = sources[activeSourceIndex] || sources[0];

  const resolvedUrl = useMemo(() => resolveSourceUrl(activeSource?.url), [activeSource]);

  const hlsConfig = useMemo(() => {
    if (!Hls.isSupported()) return {};
    return {
      fetchSetup: (url: string, init: RequestInit) => {
        const isKey = url.includes('.key') || url.includes('/keys/') || (activeSource?.keyUrl && url.includes(activeSource.keyUrl));
        if (isKey) {
          const targetUrl = activeSource?.keyUrl || url;
          return new Request(`https://test.cors.workers.dev/?${encodeURIComponent(targetUrl)}`, init);
        }
        return new Request(url, init);
      },
      xhrSetup: (xhr: XMLHttpRequest) => {
        xhr.withCredentials = false;
      },
      enableWorker: true,
    };
  }, [activeSource]);

  const handleTimeUpdate = (event: any) => {
    if (!event?.detail) return;
    const { currentTime, duration } = event.detail;
    if (duration > 0) {
      const percent = (currentTime / duration) * 100;
      onProgress?.(percent);
      if (percent >= 98) onComplete?.();
    }
  };

  const getServerLabel = (name: string) => {
    const n = name.toLowerCase();
    if (n === 'default') return { text: 'Default', experimental: true };
    if (n.includes('yt')) return { text: 'Yt-mp4', experimental: false };
    if (n.includes('s-mp4')) return { text: 'S-mp4', experimental: false };
    if (n.includes('ok')) return { text: 'Ok', experimental: false };
    return { text: name, experimental: false };
  };

  return (
    <div className="flex flex-col gap-6">
      <div className="flex flex-col lg:flex-row gap-6">
        <div className="flex-[3] relative aspect-video bg-zinc-950 rounded-2xl overflow-hidden shadow-2xl border border-white/5">
          {activeSource?.type === SourceType.EMBED ? (
            <div className="w-full h-full bg-black flex flex-col">
              <div className="flex-1">
                <iframe
                  src={resolvedUrl}
                  className="w-full h-full border-0"
                  allowFullScreen
                  sandbox="allow-scripts allow-same-origin allow-forms"
                  referrerPolicy="no-referrer"
                />
              </div>
              <div className="bg-zinc-900 px-4 py-2 border-t border-white/5 flex items-center justify-between">
                <span className="text-[10px] font-black uppercase text-zinc-500 tracking-widest">
                  Embedded Stream ({activeSource.pluginName})
                </span>
                <span className="text-[10px] text-amber-500 font-bold uppercase tracking-tighter">
                  Limited Controls
                </span>
              </div>
            </div>
          ) : (
            <MediaPlayer
              title={title}
              src={resolvedUrl}
              onTimeUpdate={handleTimeUpdate}
              crossOrigin
              playsInline
              className="w-full h-full"
            >
              <MediaProvider {...({ hlsConfig } as any)}>
                {poster && <Poster src={poster} alt={title} className="vds-poster" />}
              </MediaProvider>
              <DefaultVideoLayout icons={defaultLayoutIcons} />
            </MediaPlayer>
          )}
        </div>

        <div className="flex-1 flex flex-col gap-4">
          <div className="bg-zinc-900/50 backdrop-blur-xl rounded-2xl border border-white/5 p-5 h-full">
            <h3 className="text-[10px] font-black uppercase tracking-[0.4em] text-zinc-500 mb-6 flex items-center gap-2">
              <div className="w-1.5 h-1.5 rounded-full bg-blue-500 animate-pulse"></div>
              Server Selection
            </h3>

            <div className="grid grid-cols-1 gap-2 overflow-y-auto max-h-[300px] lg:max-h-none custom-scrollbar pr-2">
              {sources.map((source, index) => {
                const labelInfo = getServerLabel(source.pluginName);
                const isActive = activeSourceIndex === index;

                return (
                  <button
                    key={index}
                    onClick={() => setActiveSourceIndex(index)}
                    className={`group w-full flex items-center justify-between p-4 rounded-xl transition-all border ${
                      isActive 
                        ? 'bg-blue-600/10 border-blue-500/50 shadow-lg' 
                        : 'bg-zinc-800/40 border-transparent hover:bg-zinc-800 hover:border-white/10'
                    }`}
                  >
                    <div className="flex flex-col items-start">
                      <span className={`text-[11px] font-black uppercase tracking-widest ${isActive ? 'text-blue-400' : 'text-zinc-300'}`}>
                        {labelInfo.text}
                      </span>
                      <span className="text-[9px] text-zinc-600 font-bold uppercase">
                        {source.type === SourceType.EMBED ? 'Iframe' : 'Native'}
                      </span>
                    </div>
                    {labelInfo.experimental && (
                      <span className="text-[8px] bg-amber-500/10 text-amber-500 border border-amber-500/20 px-2 py-0.5 rounded-full font-black uppercase">
                        Experimental
                      </span>
                    )}
                  </button>
                );
              })}
            </div>

            <div className="mt-6 pt-6 border-t border-white/5">
              <div className="flex items-center gap-3 opacity-50">
                <div className="w-2 h-2 rounded-full bg-green-500"></div>
                <span className="text-[8px] font-black uppercase tracking-widest text-zinc-500">
                  Global Matrix Online
                </span>
              </div>
            </div>
          </div>
        </div>
      </div>

      <style>{`
        .vds-poster {
          position: absolute;
          inset: 0;
          width: 100%;
          height: 100%;
          object-fit: cover;
          opacity: 0.15;
          filter: blur(50px);
          transition: opacity 0.5s ease;
        }
        .vds-media-player[data-can-play] .vds-poster {
          opacity: 0;
          pointer-events: none;
        }
      `}</style>
    </div>
  );
};

export default AnimePlayer;

